import{_ as n,j as t,o as e,v as h}from"./chunks/framework.OlxNbC8G.js";const i=JSON.parse('{"title":"World wide web là gì ?","description":"","frontmatter":{"footer":true,"title":"World wide web là gì ?","authors":["lethanh"],"date":"2024-03-18T00:00:00.000Z","outline":"deep","draft":true},"headers":[{"level":2,"title":"World wide web là gì ?","slug":"world-wide-web-la-gi","link":"#world-wide-web-la-gi","children":[]},{"level":2,"title":"Các thành phần của WWW (World Wide Web)","slug":"cac-thanh-phan-cua-www-world-wide-web","link":"#cac-thanh-phan-cua-www-world-wide-web","children":[]},{"level":2,"title":"Các phiên bản của WWW.","slug":"cac-phien-ban-cua-www","link":"#cac-phien-ban-cua-www","children":[{"level":3,"title":"Web 1.0 (The static web)","slug":"web-1-0-the-static-web","link":"#web-1-0-the-static-web","children":[]},{"level":3,"title":"Web 2.0 (The Social Web)","slug":"web-2-0-the-social-web","link":"#web-2-0-the-social-web","children":[]}]}],"relativePath":"study/thanhlv-study-2024/2024-03-18-world-wide-web-la-gi.md","filePath":"study/thanhlv-study-2024/2024-03-18-world-wide-web-la-gi.md","lastUpdated":1710759509000}'),a={name:"study/thanhlv-study-2024/2024-03-18-world-wide-web-la-gi.md"},c=[h('<p>Trong thế giới kỹ thuật số ngày nay, World Wide Web đã trở thành một phần không thể tách rời của Internet, là nơi diễn ra hàng loạt hoạt động từ học tập, làm việc đến giải trí.</p><p>Mặc dù vậy, không phải lập trình viên nào cũng thấu hiểu hoặc nắm rõ về World Wide Web và những tầng nền vững chắc mà nó dựa trên.</p><p>Hãy cùng nhau khám phá và mở rộng kiến thức về World Wide Web, một thế giới siêu văn bản rộng lớn nằm ngay dưới đầu ngón tay chúng ta.</p><nav class="table-of-contents"><ul><li><a href="#world-wide-web-la-gi">World wide web là gì ?</a></li><li><a href="#cac-thanh-phan-cua-www-world-wide-web">Các thành phần của WWW (World Wide Web)</a></li><li><a href="#cac-phien-ban-cua-www">Các phiên bản của WWW.</a><ul><li><a href="#web-1-0-the-static-web">Web 1.0 (The static web)</a></li><li><a href="#web-2-0-the-social-web">Web 2.0 (The Social Web)</a></li></ul></li></ul></nav><h2 id="world-wide-web-la-gi" tabindex="-1">World wide web là gì ? <a class="header-anchor" href="#world-wide-web-la-gi" aria-label="Permalink to &quot;World wide web là gì ?&quot;">​</a></h2><ul><li><code>WWW</code> hay gọi chuẩn là <code>World Wide Web</code> là một hế thống thông tin toàn cầu dựa trên <a href="./2024-03-14-Internet-Internet-hoat-dong-nhu-the-nao.html">Internet</a>, cho phép người dùng truy cập vào các trang web và được liên kết với nhau thông qua siêu liên kết (hyperlinks).</li><li><code>WWW</code> là dịch vụ phổ biến nhất trên Internet, <code>WWW</code> bị nhiều người nhầm lẫn với <a href="./2024-03-14-Internet-Internet-hoat-dong-nhu-the-nao.html">Internet</a> nhưng thực chất đây là một trong những dịch vụ phổ biến của <a href="./2024-03-14-Internet-Internet-hoat-dong-nhu-the-nao.html">Internet</a> được cung cấp dưới dạng Web cho phép truy cập và chia sẻ thông tin thông qua web page dựa trên HTML và được liên kết với nhau thông qua Hyperlinks.</li><li>Như <a href="./2024-03-14-Internet-Internet-hoat-dong-nhu-the-nao.html#_4-su-bung-no-cua-world-wide-web-1990s">lịch sử đã được viết </a> WWW được phát minh bởi <a href="https://vi.wikipedia.org/wiki/Tim_Berners-Lee" target="_blank" rel="noreferrer">Tim Berners-Lee</a> vào năm 1989 và công bố vào năm 1990.</li><li><a href="https://vi.wikipedia.org/wiki/Tim_Berners-Lee" target="_blank" rel="noreferrer">Tim Berners-Lee</a> và các đồng nghiệp đã phát triển các công nghệ cơ bản như HTML, HTTP và URL để tạo lên nền tảng của WWW.</li><li>Ngày nay, <code>World Wide Web</code> là một phần không thể thiếu trong đời sống xã hội hiện đại, được sử dụng rộng rãi cho giáo dục, thông tin, giải trí, kinh doanh và nhiều lĩnh vực khác.</li></ul><h2 id="cac-thanh-phan-cua-www-world-wide-web" tabindex="-1">Các thành phần của WWW (World Wide Web) <a class="header-anchor" href="#cac-thanh-phan-cua-www-world-wide-web" aria-label="Permalink to &quot;Các thành phần của WWW (World Wide Web)&quot;">​</a></h2><p>WWW (World Wide Web) sẽ có 4 thành phần chính để có thể hoạt động.</p><ol><li><strong>HyperText Markup Language (HTML)</strong>: HTML là ngôn ngữ đánh dấu sử dụng các thẻ để tạo ra cấu trúc và nội dung cho các web page. Nó cho phép văn bảm, hình ảnh, video và nhiều dữ liệu khác được nhúng và hiển thị trên trình duyệt.</li><li><strong>HyperText Transfer Protocol (HTTP)</strong>: HTTP là giao thức truyền tải siêu văn bản, HTTP quy ước các thức dữ liệu được truyền tải trên web. Khi bạn nhập vào một URL trên trình duyệt, HTTP sẽ đưược kích hoatj</li><li><strong>Uniform Resource Locator (URL)</strong>: URL là địa chỉ của một tài nguyên trên Web, URL giúp xác định ví trị của tài nguyên trên Internet. Đến thời điểm 18-3-2014 thì URL hiện tại có 2 giao thức là Http và Https <ul><li>Cấu trúc của 1 URL gồm: Giao thức(http/https) + tên miền hoặc IP + đường dẫn tài nguyên(path)</li></ul></li><li><strong>Trình duyệt web (Web browser)</strong>: Trình duyệt là một phần mềm cho phép người dùng xem và tương tác với nội dung trên World Wide Web. Các trình duyệt phổ biến hiện tại gồm Chrome, Firefox, Safari và Edge.</li></ol><h2 id="cac-phien-ban-cua-www" tabindex="-1">Các phiên bản của WWW. <a class="header-anchor" href="#cac-phien-ban-cua-www" aria-label="Permalink to &quot;Các phiên bản của WWW.&quot;">​</a></h2><h3 id="web-1-0-the-static-web" tabindex="-1">Web 1.0 (The static web) <a class="header-anchor" href="#web-1-0-the-static-web" aria-label="Permalink to &quot;Web 1.0 (The static web)&quot;">​</a></h3><ul><li><strong>Thời gian</strong>: Khoảng 1991 - 2000</li><li><strong>Đặc điểm</strong>: <ul><li>Web 1.0 là phiên bản đầu tiên của World Wide Web, phiên bản này thường được gọi là <code>Web tĩnh</code>.</li><li>Các trang web sẽ chỉ chứa các thông tin tĩnh và chỉ có thể đọc, không thể tương tác hoặc cập nhật dữ liệu bởi người dùng.</li><li>Thời điểm đầu tiên các trang web chỉ có HTML. Đến năm 1995 Javascript ra đời và 1996 Css 1.0 ra đời nhưng nó vẫn rất hạn chế và ít được sử dụng. <ul><li>Tại giai đoạn này Css và Javascript vẫn chưa có chuẩn chung, các trình duyệt vẫn chưa tích hợp đồng nhất nên có nhiều sự khác biệt khi hiển thị trên các trình duyệt khác nhau.</li></ul></li><li>Các trang web chỉ có thể cập nhật dữ liệu bởi các nhà phát triển hoặc chủ sở hữu Web, người dùng không thể cập nhật.</li></ul></li></ul><h3 id="web-2-0-the-social-web" tabindex="-1">Web 2.0 (The Social Web) <a class="header-anchor" href="#web-2-0-the-social-web" aria-label="Permalink to &quot;Web 2.0 (The Social Web)&quot;">​</a></h3>',13)];const l=n(a,[["render",function(n,h,i,a,l,r){return e(),t("div",null,c)}]]);export{i as __pageData,l as default};
